INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00040', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「善良的人無法喜愛一件新的作品，但當這作品問世二十年後卻又真誠地 喜愛它，這是常有的事。新生命的香味太濃了，他們虛弱的頭腦承受不了， 香氣會隨著時間的流逝而漸漸揮發掉。藝術品只有在覆滿陳年積垢時才會 被他們理解。」 根據上文，下列選項何者最符合文意？', '["人類大多是善變無常", "只有強者才善於創造", "創作者難免承受孤獨", "善良無助於評價優劣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00041', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「雖然組織胺的主要任務是保護身體的安全，但是這些保鑣有時對很多東 西都視為威脅。例如飄在空氣中的花粉，或家中寵物的毛髮、皮屑，組織 胺都想要把它們擋在身體之外，而下達排除的指令。這些會引發身體組織 胺大量分泌的外界物質稱為『過敏原』，這些物質引發的身體反應稱為『過 敏』。」 根據上文，下列選項何者與上文所言相抵觸？', '["組織胺就像體內保鑣多多益善", "過敏原會引發身體大量分泌組織胺", "花粉或寵物的毛髮、皮屑都有可能是過敏原", "過敏是對自然環境中的過敏原產生反應的現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00042', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '村上春樹曾說過：「不管多大年紀都無所謂，無非就是個恰到好處的人罷 了。」不必非得去裝年輕，也不必去感慨歲月滄桑，「花開花落自有時」， 追隨大自然的規律，一切都剛剛好！ 根據上文，下列選項最符合文意的是：', '["健康長壽是老年人最大的幸福", "努力改變自己，讓自己活得更精彩", "不管什麼年齡，接納自己，好壞都自有安排", "年輕時就該為老年計劃，才不至於老大徒傷悲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00043', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「電車通過櫻花隧道之際，也讓人湧起一股如夢似幻的感受，難道這輛穿 越花海的電車，最終會開往夢幻天堂？京都的美經常給人一種不真實感， 美到讓人無法呼吸，讓人無法忍受，最後不得不像《金閣寺》裡的小和尚， 忍不住一把火將金閣寺燒掉！日本的櫻花美學就是要去擁抱、珍惜短暫的 極致美感，美的極致之後，就不在乎毀滅或死亡了！」 根據上文，下列選項何者最符合文意？', '["櫻花盛開有如熊熊火焰，似乎要將一切景物吞沒殆盡", "櫻花盛開時的美感極為短暫虛幻，所以不能沉迷其中", "人們若曾經領略如櫻花盛放的美好片刻，就了無遺憾", "小和尚在櫻花盛開之時縱火焚寺，是殉美的極致表現"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00044', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「處理報導內容的重要區塊時，記者要像嚮導一樣。他提出門外漢都會做 的謹慎結論，但也必須列出一些證據來佐證那些結論。如果沒有證據，文 章會顯得自以為是，空洞不實。不過，在文章的邊緣區塊，記者不再只是 嚮導，他可以利用讀者賦予的代理權，為讀者提供臨場感及人物的實感。」 根據上文，下列選項最符合文意的是：', '["記者報導應該致力突破文章邊界，爭取讀者代理權", "報導以詳細證據輔助結論，並從讀者角度強化感受", "新聞報導通常只會給出常人可知的結論，以免犯錯", "新聞報導追求臨場感與人物實感，反而削減證據力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00045', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「AI的本質是去取代人的腦力，也就是所謂的專家智慧；而法律的本質， 不純粹是追求價值觀的維護，而更傾向是經濟、政治、科技改變下的產物。 在可預見的未來，AI技術即將衝擊到法律的解釋適用，而當社會進一步受 到 AI 衝擊後，應運而生的將是許多因應 AI 的修法，如 AI 篩選面試者的 機制可能造成的歧視、隱私權問題。」 下列敘述何者正確？', '["AI智慧將會完全取代專家", "AI科技不會衝擊人文法律", "AI的本質是追求絕對價值", "AI執行仍須專家整合思考"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00046', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「聯合國在2022年發布的2023人口報告中就警告，所有國家都需要為人 口老化的現實做好準備。因為社會與經濟的衰老與停滯是大多數富裕國家 與中等收入國家被迫面對的共同難題。生存狀況顯著改善與生育率下降， 已經讓人口老化成為這個時代不可逆轉的全球趨勢，越晚面對人口老化問 題，所要負擔的社會、經濟、財政和衛生成本將越高昂。」 根據上文，關於人口老化的原因，下列推論何者正確？', '["富裕與中等收入國家的政策是造成人口老化的原因", "經濟不斷衰退，造成人口老化，這是目前全球所面臨的難題", "因為衛生成本逐年增加，導致經濟停滯，間接影響國家的生存狀況", "生育率下降與生存狀況的改善，讓人口老化成為全球共同面臨的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00047', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「臺灣森林分為天然林與人工林，目前天然林因保育而全面禁伐，但人工 林則否。在世界提倡淨碳排的趨勢下，森林『碳匯』議題越來越被重視—— 意即森林具有固碳功能，可以將二氧化碳吸存固著於自然環境中，形成如 同把錢存在銀行一樣的倉庫。因此，要增加碳匯，就必須多造林。然而， 樹木會老化，過了 20 年的生長巔峰期，固碳能力逐年下降，最後失去固 碳功能，是以人工林的更新有其必要性。」 根據上文，下列選項最符合文意的是：', '["樹齡越大、枝葉越茂盛，對環境保護的效益越大", "人工林的造林和定期採伐，有其實質上的必要性", "環境意識的崛起，禁伐已是全球山林保育的趨勢", "天然林比人工林更具有碳匯的效益，可增加獲利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00048', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '某企業代表在產業高峰會中表示：「為了能招募外國人才，加上臺灣環境 資源有限，包括土地、水、電，走出臺灣是不得不做的事情。然而在海外 布局的過程面臨兩個挑戰，首先是全球人才不足，不僅人口變少，念半導 體的人也變少。另一個挑戰是文化融合，應以開放心態因應。全球化布局 可能造成成本增加，增加的成本是由客戶吸收，或企業自行吸收，將會是 挑戰，也是企業全球化要面對的議題。」 根據上文，下列選項何者正確？', '["產業發展必須倚賴全球人才，但也要考慮文化融合的衝擊", "受新冠肺炎疫情影響，人才流動受限，因此必須走出臺灣", "為了產品標準化，應該統一各地製程、管理、營運之步驟", "全球布局能利用各地廉價的勞工、土地、水電，降低成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00049', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「一葉知秋，一根頭髮可以讓罪犯無所遁形。可見，頭髮就是人這棵樹的 葉子。秋天到了，葉轉黃，年紀大了，髮變白。人與時間拔河，以白髮為 繩。老，本是自然律裡的事，擋不了也無須擋。一派天真自然，反而能使 『老』這件事顯出美好的部分。我不討厭白髮，有時還覺得有些人的白髮 長得真好看。如果一棵樹的葉子綠得像幫派，看久了會膩，若泛起霜紅色 澤，美就來了。人亦如此，渾身上下要一起老才好。白髮是落雪天氣，人 生走到這一步，離暴動份子的時代遠了，較接近沉思的智者。」 根據上文，下列選項何者最符合文意？', '["活到老，學到老", "老吾老，以及人之老", "夕陽無限好，正是近黃昏", "人間只道黃金貴，不問天公買少年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
